## Recovery Strategies

| Failure | Detection | Recovery |
|---------|-----------|----------|
| Rebase conflict | Non-zero exit + conflict markers | Abort rebase, report conflicts, let agent/human resolve |
| Merge conflict | Non-zero exit + conflict markers | Abort merge, report conflicts |
| Corrupted worktree | Git status fails | Delete and recreate worktree |
| DB/Git desync | Stream in DB but not git | Recreate branch from recorded base, or mark stream as broken |
| Crashed mid-operation | Operation started but not completed | On restart, check for uncommitted state, rollback or complete |

## Recovery Implementations

### Conflict Recovery

```typescript
function recoverFromConflict(
  worktree: string,
  operation: 'rebase' | 'merge'
): void {
  if (operation === 'rebase') {
    execSync('git rebase --abort', { cwd: worktree });
  } else {
    execSync('git merge --abort', { cwd: worktree });
  }
}
```

### Worktree Recovery

```typescript
function recoverWorktree(
  repoPath: string,
  worktreePath: string,
  agentId: string
): void {
  // Remove corrupted worktree
  try {
    execSync(`git worktree remove --force ${worktreePath}`, { cwd: repoPath });
  } catch {
    // Worktree might already be gone
  }

  // Clean up filesystem if needed
  if (fs.existsSync(worktreePath)) {
    fs.rmSync(worktreePath, { recursive: true });
  }

  // Recreate
  execSync(`git worktree add ${worktreePath} main`, { cwd: repoPath });

  // Update database
  db.prepare(`
    UPDATE agent_worktrees
    SET current_stream = NULL, last_active = ?
    WHERE agent_id = ?
  `).run(Date.now(), agentId);
}
```

### DB/Git Desync Recovery

```typescript
interface DesyncRecoveryResult {
  action: 'recreated' | 'marked_broken' | 'removed';
  details: string;
}

function recoverDesync(
  tracker: MultiAgentRepoTracker,
  streamId: string
): DesyncRecoveryResult {
  const stream = tracker.getStream(streamId);

  // Check if branch exists
  try {
    execSync(`git rev-parse stream/${streamId}`, { cwd: tracker.repoPath });
    // Branch exists but DB is wrong - sync from git
    return { action: 'recreated', details: 'Synced DB from git state' };
  } catch {
    // Branch doesn't exist
  }

  // Check if base commit exists
  try {
    execSync(`git rev-parse ${stream.baseCommit}`, { cwd: tracker.repoPath });
    // Can recreate branch from base
    execSync(
      `git branch stream/${streamId} ${stream.baseCommit}`,
      { cwd: tracker.repoPath }
    );
    return { action: 'recreated', details: 'Recreated branch from base commit' };
  } catch {
    // Base commit is gone too
  }

  // Mark as broken
  tracker.db.prepare(`
    UPDATE streams SET status = 'broken', metadata = json_set(metadata, '$.error', ?)
    WHERE id = ?
  `).run('Base commit not found, cannot recover', streamId);

  return {
    action: 'marked_broken',
    details: 'Base commit not found, stream marked as broken'
  };
}
```

### Partial Operation Recovery

```typescript
interface OperationCheckpoint {
  operationId: string;
  streamId: string;
  opType: string;
  step: number;
  totalSteps: number;
  beforeState: string;
  currentState: string;
  startedAt: number;
}

class OperationRecovery {
  private db: Database;

  /**
   * Check for incomplete operations on startup.
   */
  checkForIncomplete(): OperationCheckpoint[] {
    return this.db.prepare(`
      SELECT * FROM operation_checkpoints
      WHERE step < total_steps
      ORDER BY started_at DESC
    `).all();
  }

  /**
   * Record checkpoint during multi-step operation.
   */
  checkpoint(data: OperationCheckpoint): void {
    this.db.prepare(`
      INSERT OR REPLACE INTO operation_checkpoints
      (operation_id, stream_id, op_type, step, total_steps, before_state, current_state, started_at)
      VALUES (?, ?, ?, ?, ?, ?, ?, ?)
    `).run(
      data.operationId,
      data.streamId,
      data.opType,
      data.step,
      data.totalSteps,
      data.beforeState,
      data.currentState,
      data.startedAt
    );
  }

  /**
   * Clear checkpoint after successful completion.
   */
  complete(operationId: string): void {
    this.db.prepare('DELETE FROM operation_checkpoints WHERE operation_id = ?')
      .run(operationId);
  }

  /**
   * Recover from incomplete operation.
   */
  recover(checkpoint: OperationCheckpoint, worktree: string): void {
    // Roll back to before_state
    execSync(
      `git reset --hard ${checkpoint.beforeState}`,
      { cwd: worktree }
    );

    // Remove checkpoint
    this.complete(checkpoint.operationId);

    console.log(`Recovered operation ${checkpoint.operationId}: reset to ${checkpoint.beforeState}`);
  }
}
```

## Startup Recovery Flow

```typescript
async function startupRecovery(tracker: MultiAgentRepoTracker): Promise<void> {
  const recovery = new OperationRecovery(tracker.db);

  // Check for incomplete operations
  const incomplete = recovery.checkForIncomplete();

  for (const checkpoint of incomplete) {
    console.log(`Found incomplete operation: ${checkpoint.operationId}`);

    // Get worktree for this stream
    const worktree = tracker.getWorktreeForStream(checkpoint.streamId);

    if (worktree) {
      recovery.recover(checkpoint, worktree);
    } else {
      console.warn(`No worktree for stream ${checkpoint.streamId}, removing checkpoint`);
      recovery.complete(checkpoint.operationId);
    }
  }

  // Check for stale locks
  const staleLocks = tracker.db.prepare(`
    SELECT * FROM stream_locks WHERE acquired_at < ?
  `).all(Date.now() / 1000 - 300);  // 5 minutes

  for (const lock of staleLocks) {
    console.log(`Releasing stale lock on stream ${lock.stream_id} held by ${lock.agent_id}`);
    tracker.streamLock.release(lock.stream_id, lock.agent_id);
  }
}
